// src/pages/SemesterSelection.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSemestersForYear } from '../services/api';
import { getCourseById } from '../config/config';

const SemesterSelection = () => {
  const { courseId, yearId } = useParams();
  const navigate = useNavigate();
  const [semesters, setSemesters] = useState([]);
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSemestersData();
  }, [courseId, yearId]);

  const fetchSemestersData = async () => {
    try {
      // Get course info from config
      const courseData = getCourseById(courseId);
      setCourse(courseData);

      // Try to get semesters from API
      let semestersData;
      try {
        semestersData = await getSemestersForYear(courseId, parseInt(yearId));
      } catch (apiError) {
        console.log('API failed, using fallback data');
        // Fallback semesters data
        semestersData = [
          { id: 1, name: 'Semester 1', subjects: 6, credits: 24 },
          { id: 2, name: 'Semester 2', subjects: 6, credits: 24 },
          { id: 3, name: 'Semester 3', subjects: 7, credits: 28 },
          { id: 4, name: 'Semester 4', subjects: 7, credits: 28 }
        ];
      }

      setSemesters(semestersData);
    } catch (error) {
      console.error('Error fetching semesters:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSemesterClick = (semesterId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semesterId}`);
  };

  const handleBack = () => {
    navigate(`/course/${courseId}`);
  };

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p>Loading semesters...</p>
      </div>
    );
  }

  if (!course) {
    return (
      <div style={styles.errorContainer}>
        <h3>Course not found!</h3>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Courses
        </button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Years
        </button>
        <div style={styles.pageHeader}>
          <h1 style={styles.title}>
            <span style={styles.courseIcon}>{course.icon}</span>
            {course.name} - Year {yearId}
          </h1>
          <p style={styles.subtitle}>Select your semester</p>
        </div>
      </div>

      {/* Semesters Grid */}
      <div style={styles.semestersGrid}>
        {semesters.map((semester) => (
          <div
            key={semester.id}
            style={styles.semesterCard}
            onClick={() => handleSemesterClick(semester.id)}
          >
            <div style={styles.semesterHeader}>
              <div style={styles.semesterNumber}>{semester.id}</div>
              <h3 style={styles.semesterName}>{semester.name}</h3>
            </div>
            
            <div style={styles.semesterInfo}>
              <div style={styles.infoItem}>
                <span style={styles.infoLabel}>Subjects:</span>
                <span style={styles.infoValue}>{semester.subjects}</span>
              </div>
              <div style={styles.infoItem}>
                <span style={styles.infoLabel}>Credits:</span>
                <span style={styles.infoValue}>{semester.credits}</span>
              </div>
            </div>
            
            <div style={styles.materialsList}>
              <span style={styles.materialBadge}>Syllabus</span>
              <span style={styles.materialBadge}>Notes</span>
              <span style={styles.materialBadge}>PYQs</span>
              <span style={styles.materialBadge}>Lab Files</span>
            </div>
            
            <button style={styles.viewButton}>
              View Subjects →
            </button>
          </div>
        ))}
      </div>

      {/* Year Info */}
      <div style={styles.yearInfo}>
        <h3>📚 Year {yearId} Information</h3>
        <p>
          Total Semesters: {semesters.length} • 
          Total Credits: {semesters.reduce((sum, sem) => sum + sem.credits, 0)} • 
          Total Subjects: {semesters.reduce((sum, sem) => sum + sem.subjects, 0)}
        </p>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  },
  header: {
    marginBottom: '2rem'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '1rem',
    marginBottom: '1rem',
    display: 'inline-block',
    transition: 'all 0.3s',
    '&:hover': {
      background: '#4338ca',
      transform: 'translateX(-5px)'
    }
  },
  pageHeader: {
    background: 'white',
    padding: '2rem',
    borderRadius: '15px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  courseIcon: {
    fontSize: '2rem',
    marginRight: '0.5rem',
    verticalAlign: 'middle'
  },
  title: {
    fontSize: '2rem',
    marginBottom: '0.5rem',
    color: '#1f2937'
  },
  subtitle: {
    color: '#6b7280',
    fontSize: '1.1rem'
  },
  semestersGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '1.5rem',
    marginBottom: '2rem'
  },
  semesterCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    cursor: 'pointer',
    transition: 'all 0.3s',
    border: '2px solid transparent',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      borderColor: '#4f46e5',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    }
  },
  semesterHeader: {
    display: 'flex',
    alignItems: 'center',
    gap: '1rem',
    marginBottom: '1rem'
  },
  semesterNumber: {
    width: '50px',
    height: '50px',
    background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '1.5rem',
    fontWeight: 'bold',
    color: 'white',
    boxShadow: '0 4px 10px rgba(79, 70, 229, 0.3)'
  },
  semesterName: {
    fontSize: '1.25rem',
    color: '#1f2937'
  },
  semesterInfo: {
